Here's an example of how you can achieve this using a dictionary to store the caches, where the keys are the index file names and the values are the caches:

```python
from typing import Dict, Any

class IndexCache:
    def __init__(self):
        self.caches: Dict[str, Any] = {}

    def get_cache(self, index_file: str) -> Any:
        """Get the cache for a given index file."""
        return self.caches.get(index_file)

    def set_cache(self, index_file: str, cache: Any) -> None:
        """Set the cache for a given index file."""
        self.caches[index_file] = cache

    def delete_cache(self, index_file: str) -> None:
        """Delete the cache for a given index file."""
        if index_file in self.caches:
            del self.caches[index_file]
