import { createContext, useContext, useState } from 'react';
import { notify } from './notification.helpers';

interface NotificationContextInterface {
  notificationElem: HTMLHuelNotificationElement | null;
  triggerNotification: (props: Parameters<typeof notify>[1]) => Promise<void>;
}

const NotificationContext = createContext<NotificationContextInterface>({} as NotificationContextInterface);

const useNotificationContext = () => {
  const notificationElem = useContext(NotificationContext);
  const [triggerNotification, setTriggerNotification] = useState<((props: Parameters<typeof notify>[1]) => Promise<void>)>(() => async (props) => {
    if (!notificationElem) return;
    try {
      await notify(notificationElem, props);
    } catch (error) {
      console.error(error);
    }
  });

  return { notificationElem, triggerNotification };
};

export { NotificationContext, useNotificationContext };
